 public sealed class ServiceRegistryResult { public Gi.Batch.Shared.Runtime.IJobOrchestrator Orchestrator { get; set; } }
 public static class ServiceRegistry { public static ServiceRegistryResult Build(string[] args) { var rawConfiguration = EjendomTjekEjerskifteConfigurationFactory.CreateRaw(args); var settings = EjendomTjekEjerskifteConfigurationFactory.CreateSettings(rawConfiguration); var startupDiagnostics = EjendomTjekEjerskifteStartupDiagnostics.Build(rawConfiguration, settings); EjendomTjekEjerskifteStartupDiagnostics.WriteToConsole(startupDiagnostics); EjendomTjekEjerskifteSettingsValidator.Validate(settings); var logger = JobLoggerFactory.Create(settings); var request = EjendomTjekEjerskifteRequestFactory.Create(rawConfiguration, settings); IFailureNotifier notifier = new ConfigurableFailureNotifier(rawConfiguration, settings.FailureRecipients); IEjendomTjekEjerskifteScanClientFactory scanClientFactory = new EjendomTjekEjerskifteDataverseClientFactory(settings, logger); IEjendomTjekEjerskifteJobPublisher jobPublisher = new EjendomTjekEjerskifteJobPublisher(settings, new EjendomTjekEjerskifteServiceBusSender(settings, logger), logger); IEjendomTjekEjerskifteWorkflow workflow = new EjendomTjekEjerskifteDataverseWorkflow(settings, scanClientFactory, jobPublisher, logger); IEjendomTjekEjerskifteGateway gateway = new EjendomTjekEjerskifteCrmGateway(settings, workflow, logger); IEjendomTjekEjerskifteCrmConnectionVerifier crmConnectionVerifier = new EjendomTjekEjerskifteCrmConnectionVerifier(scanClientFactory, logger); var guard = new SingleInstanceGuard(settings); var failureNotificationService = new FailureNotificationService(settings, notifier); var orchestrator = new EjendomTjekEjerskifteOrchestrator(settings, request, guard, gateway, crmConnectionVerifier, failureNotificationService, logger); return new ServiceRegistryResult { Orchestrator = orchestrator }; } }
